 * Classification Results Persistence Layer (T043) - Prisma Implementation
 *
 * Repository pattern for classification results persistence using Prisma ORM:
 * - Classification session management (create, update, complete)
 * - Classification results with explainability traces
 * - Score breakdown persistence
 * - Attribute context storage
 * - Multi-label classification support
 * - Domain signal resolutions
 * - Transaction-safe batch operations
 *
 * Benefits of Prisma ORM:
 * - Type-safe database queries with auto-generated types
 * - Built-in transaction handling for complex multi-table operations
 * - Automatic JSON serialization/deserialization for explainability data
 * - Connection pooling and query optimization
 * - SQL injection protection via parameterized queries
 */

import { PrismaClient, Prisma } from '@prisma/client';
import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';

/**
 * Domain signal resolution data structure
 */
export interface DomainSignalData {
  domain: string;
  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
  matchedCategoryId: number | null;
  confidenceLevel?: string;
  domainType?: string;
}

/**
 * Classification Repository using Prisma ORM
 *
 * Provides type-safe classification results persistence with automatic transaction
 * handling, connection pooling, and explainability trace integrity.
 */
export class ClassificationRepository {
  private readonly prisma: PrismaClient;
  private readonly ownsPrisma: boolean;

  /**
   * Initialize classification repository
   *
   * @param prisma - Optional Prisma client instance (creates default if not provided)
   */
  constructor(prisma?: PrismaClient) {
    if (prisma) {
      this.prisma = prisma;
      this.ownsPrisma = false;
    } else {
      this.prisma = new PrismaClient();
      this.ownsPrisma = true;
    }
  }

  /**
   * Create a new classification session
   *
   * @param session - ClassificationSession object
   * @param gmailId - Gmail message ID being classified
   * @returns Database session ID as string (safe representation of bigint)
   * @throws {Error} If session creation fails
   */
  async createSession(session: ClassificationSession, gmailId: string): Promise<string> {
    try {
      const result = await this.prisma.classificationSession.create({
        data: {
          gmailId: gmailId,
          pipelineVersion: session.configVersion,
          startedAt: session.startedAt,
          status: 'in_progress',
          triggeredBy: 'system',
          aiRoutingUsed: false,
        },
      });

      return result.sessionId.toString();
    } catch (error) {
      throw new Error(
        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Complete a classification session
   *
   * @param sessionId - Session identifier as string (from createSession)
   * @param finalCategoryId - Final category ID selected
   * @param confidence - Final confidence score
   * @param rationale - Final decision rationale
   * @throws {Error} If session update fails
   */
  async completeSession(
    sessionId: string,
    finalCategoryId: number,
    confidence: number,
    rationale: string
  ): Promise<void> {
    try {
      // Convert string session ID to BigInt for database query
      const dbSessionId = BigInt(sessionId);

      await this.prisma.classificationSession.update({
        where: { sessionId: dbSessionId },
        data: {
          completedAt: new Date(),
          finalCategoryId: finalCategoryId,
          finalConfidence: new Prisma.Decimal(confidence),
          finalRationale: rationale,
          status: 'completed',
        },
      });
    } catch (error) {
      throw new Error(
        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Save complete classification result with explainability trace
   *
   * Uses Prisma transaction to ensure atomicity across multiple tables:
   * - classification_stage (9 pipeline stages)
   * - stage_category_eval (per-category evaluations)
   * - session_categories (multi-label support)
   * - detected_attributes (attribute context)
   * - domain_signal_resolutions (domain signals)
   *
   * @param result - ClassificationResult with explainability trace
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If save fails (rolls back entire transaction)
   */
  async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
    try {
      const dbSessionId = BigInt(sessionId);

      await this.prisma.$transaction(async (tx) => {
        // 1. Create classification stages (9 pipeline stages: hard assertions through audit trail)
        const stageData = this.buildStageData(result, dbSessionId);
        if (stageData.length > 0) {
          await tx.classificationStage.createMany({ data: stageData });
        }

        // 2. Create stage category evaluations (score breakdown for each category)
        const categoryEvalData = this.buildCategoryEvalData(result, dbSessionId);
        if (categoryEvalData.length > 0) {
          await tx.stageCategoryEval.createMany({ data: categoryEvalData });
        }

        // 3. Create session categories (multi-label support)
        const sessionCategoryData = this.buildSessionCategoryData(result, dbSessionId);
        if (sessionCategoryData.length > 0) {
          await tx.sessionCategory.createMany({ data: sessionCategoryData });
        }

        // 4. Create detected attributes (attribute context)
        const attributeData = this.buildAttributeData(result.attributeContext, dbSessionId);
        if (attributeData.length > 0) {
          await tx.detectedAttribute.createMany({ data: attributeData });
        }
      });
    } catch (error) {
      throw new Error(
        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Save attribute context separately
   *
   * @param context - AttributeContext with detected attributes
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If save fails
   */
  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
    try {
      const dbSessionId = BigInt(sessionId);
      const attributeData = this.buildAttributeData(context, dbSessionId);
      if (attributeData.length > 0) {
        await this.prisma.detectedAttribute.createMany({ data: attributeData });
      }
    } catch (error) {
      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Save domain signal resolutions
   *
   * @param signals - Array of domain signal resolutions
   * @param sessionId - Session identifier as string (from createSession)
   * @throws {Error} If save fails
   */
  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
    if (signals.length === 0) {
      return;
    }

    try {
      const dbSessionId = BigInt(sessionId);
      await this.prisma.domainSignalResolution.createMany({
        data: signals.map((signal) => ({
          sessionId: dbSessionId,
          domain: signal.domain,
          signalType: signal.signalType,
          matchedCategoryId: signal.matchedCategoryId,
          confidenceLevel: signal.confidenceLevel || null,
          domainType: signal.domainType || null,
          createdAt: new Date(),
        })),
      });
    } catch (error) {
      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Batch save multiple classification results
   *
   * @param results - Array of ClassificationResult objects
   * @param dbSessionId - Database session ID
   * @throws {Error} If batch save fails
   */
  async batchSaveResults(results: ClassificationResult[], dbSessionId: number): Promise<void> {
    if (results.length === 0) {
      return;
    }

    try {
      // Save each result sequentially within a transaction
      for (const result of results) {
        await this.saveClassificationResult(result, dbSessionId);
      }
    } catch (error) {
      throw new Error(
        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Build classification stage data from explainability trace
   */
  private buildStageData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.ClassificationStageCreateManyInput> {
    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
    const trace = result.explainabilityTrace;

    // Map pipeline stages to database records
    const stageMapping = [
      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
      { order: 6, type: 'disambiguation', data: trace.disambiguation },
      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
      { order: 8, type: 'ai_routing', data: trace.aiRouting },
      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
    ];

    for (const stage of stageMapping) {
      stages.push({
        sessionId: sessionId,
        stageOrder: stage.order,
        stageType: stage.type,
        startedAt: new Date(),
        endedAt: new Date(),
        features: stage.data as Prisma.InputJsonValue,
        keywords: [],
        passedToNext: true,
      });
    }

    return stages;
  }

  /**
   * Build stage category evaluation data from score breakdown
   */
  private buildCategoryEvalData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.StageCategoryEvalCreateManyInput> {
    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
    const scoreBreakdown = result.scoreBreakdown;

    // Extract category scores and create evaluations
    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
      evaluations.push({
        stageId: sessionId, // Simplified: using session_id as stage_id for MVP
        categoryId: this.getCategoryIdFromCode(category),
        decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
        score: scores as unknown as Prisma.InputJsonValue,
        confidence: new Prisma.Decimal(scores.finalScore || 0),
        scoringComponents: scores as unknown as Prisma.InputJsonValue,
        keywords: [],
        createdAt: new Date(),
      });
    }

    return evaluations;
  }

  /**
   * Build session category data (multi-label support)
   */
  private buildSessionCategoryData(
    result: ClassificationResult,
    sessionId: bigint
  ): Array<Prisma.SessionCategoryCreateManyInput> {
    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];

    for (const label of result.selectedLabels) {
      categories.push({
        sessionId: sessionId,
        categoryId: this.getCategoryIdFromCode(label.category),
        subtypeId: label.subtype ? this.getCategoryIdFromCode(label.subtype) : null,
        isPrimary: label.isPrimary,
        confidence: new Prisma.Decimal(label.confidence),
        categoryScore: new Prisma.Decimal(label.score),
        hardAssertion: false, // TODO: Extract from explainability trace
        aiClassified: result.aiRoutingUsed,
        scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
        labelOrder: label.labelOrder,
        createdAt: new Date(),
      });
    }

    return categories;
  }

  /**
   * Build detected attribute data from attribute context
   */
  private buildAttributeData(
    context: AttributeContext,
    sessionId: bigint
  ): Array<Prisma.DetectedAttributeCreateManyInput> {
    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];

    // Add urgency attribute
    attributes.push({
      sessionId: sessionId,
      attributeName: 'urgency',
      attributeValue: context.urgency,
      detectionMethod: 'rule',
      detectionEvidence: 'Urgency level detection',
      influenceRole: 'FILTER',
      categoriesInfluenced: [],
      totalBonusApplied: new Prisma.Decimal(0),
      createdAt: new Date(),
    });

    // Add domain attributes
    for (const domain of context.domains) {
      attributes.push({
        sessionId: sessionId,
        attributeName: `domain:${domain}`,
        attributeValue: domain,
        detectionMethod: 'domain_lookup',
        detectionEvidence: `Domain ${domain} detected`,
        influenceRole: 'CORE',
        categoriesInfluenced: [],
        totalBonusApplied: new Prisma.Decimal(0),
        createdAt: new Date(),
      });
    }

    // Add structural pattern attributes
    for (const pattern of context.structuralPatterns) {
      attributes.push({
        sessionId: sessionId,
        attributeName: `pattern:${pattern}`,
        attributeValue: pattern,
        detectionMethod: 'regex',
        detectionEvidence: `Pattern ${pattern} matched`,
        influenceRole: 'SECONDARY_BOOST',
        categoriesInfluenced: [],
        totalBonusApplied: new Prisma.Decimal(0),
        createdAt: new Date(),
      });
    }

    return attributes;
  }

  /**
   * Get category ID from category code
   *
   * TODO: Implement proper category lookup (load from database or config)
   * For now, using simple hash function to generate consistent IDs
   */
  private getCategoryIdFromCode(code: string): number {
    // Simple hash function for MVP - replace with actual database lookup
    let hash = 0;
    for (let i = 0; i < code.length; i++) {
      hash = (hash << 5) - hash + code.charCodeAt(i);
      hash = hash & hash; // Convert to 32-bit integer
    }
    return Math.abs(hash) % 1000; // Return ID in range 0-999
  }

  /**
   * Close the Prisma client connection
   *
   * Only closes if using default Prisma instance (not externally provided).
   */
  async close(): Promise<void> {
    if (this.ownsPrisma) {
      await this.prisma.$disconnect();
    }
  }
}

