  const mockPrismaClient: any = {
    classificationSession: {
      create: jest.fn(),
      update: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
    },
    classificationStage: {
      create: jest.fn(),
      createMany: jest.fn(),
    },
    stageCategoryEval: {
      createMany: jest.fn(),
    },
    sessionCategory: {
      createMany: jest.fn(),
    },
    detectedAttribute: {
      createMany: jest.fn(),
    },
    domainSignalResolution: {
      createMany: jest.fn(),
    },
    $transaction: jest.fn((callback) => callback(mockPrismaClient)),
    $disconnect: jest.fn(),
  };

  // Mock Prisma Decimal class
  class MockDecimal {
    value: number;
    constructor(value: number | string) {
      this.value = typeof value === 'string' ? parseFloat(value) : value;
    }
    toString() {
      return this.value.toString();
    }
    toNumber() {
      return this.value;
    }
  }

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      Decimal: MockDecimal,
    },
  };
});

